INSERT INTO ich_inheritor (id, name, gender, birth_year, region_id, title, avatar, introduction, representative_works, status, created_at, updated_at, deleted) VALUES
(1, '任本荣', '男', NULL, 1, '汉绣国家级代表性传承人', NULL, '长期从事汉绣保护、创作与教学推广，是公开报道中经常出现的汉绣代表性人物。', '汉绣保护传承与技法整理', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(2, '陈伯华', '女', 1930, 1, '汉剧国家级代表性传承人', NULL, '汉剧表演艺术家，是湖北汉剧的重要代表人物，具有较高社会认知度和历史影响力。', '汉剧表演艺术传承', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(3, '钟云龙', '男', 1964, 3, '武当武术代表性传承人', NULL, '长期从事武当武术传授与传播，在武当文化推广和海内外展示中具有较高知名度。', '武当拳法与武当养生功法', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(4, '雷远贵', '男', NULL, 13, '恩施玉露制作技艺代表性传承人', NULL, '从事恩施玉露传统制茶工艺保护与传授，熟悉蒸青绿茶核心工序。', '恩施玉露传统蒸青制作', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(5, '马又甫', '男', 1950, 14, '沔阳雕花剪纸代表性传承人', NULL, '公开资料中较常见的仙桃雕花剪纸传承人，擅长传统纹样整理与教学展示。', '沔阳雕花剪纸纹样创作', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(6, '石九梅', '女', 1951, 10, '黄梅挑花代表性传承人', NULL, '黄梅挑花项目的代表性传承人之一，长期参与挑花技艺保护与作品展演。', '黄梅挑花传统针法', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(7, '曹小琴', '女', NULL, 6, '鄂州雕花剪纸代表性传承人', NULL, '擅长鄂州雕花剪纸的图案设计和展示传播，是公开报道中较常见的代表性人物。', '鄂州剪纸创作与传播', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(8, '韩善明', '男', 1966, 10, '蕲春艾灸疗法代表性传承人', NULL, '长期参与蕲春艾灸疗法临床和传播，具备较强的医药类项目演示价值。', '蕲春艾灸疗法临床推广', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(9, '何建刚', '男', NULL, 4, '长盛川青砖茶制作技艺代表性传承人', NULL, '参与长盛川青砖茶传统工艺保护与制茶流程整理，是公开报道中的重点人物。', '青砖茶传统发酵与陈化工艺', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(10, '刘洁', '女', NULL, 1, '武汉面塑代表性传承人', NULL, '在武汉面塑项目的展示、教学和文创传播中较为活跃，适合作为公众端人物案例。', '武汉面塑造型设计', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(11, '彭肖肖', '女', 1991, 2, '大冶刺绣第六代传承人', NULL, '公开报道中较具代表性的年轻传承人，体现湖北传统刺绣项目的年轻化传承方向。', '大冶刺绣创新传承', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(12, '吴培义', '男', NULL, 15, '荆州花鼓戏代表性传承人', NULL, '长期从事花鼓戏表演和传承工作，是湖北地方戏曲活态传承的典型人物。', '荆州花鼓戏唱腔与表演', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(13, '韩进', '男', NULL, 10, '蕲春艾灸疗法传承人', NULL, '参与蕲春艾灸疗法技艺推广和临床实践，用于展示医药类项目的多传承人结构。', '艾灸实践与推广', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(14, '何功威', '男', NULL, 4, '长盛川青砖茶制作技艺传承人', NULL, '参与青砖茶传统制作流程展示，适合与长盛川青砖茶项目共同演示多传承人关系。', '青砖茶工艺展示', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(15, '刘小红', '女', NULL, 2, '大冶刺绣代表性传承人', NULL, '长期从事大冶刺绣传承和教学，体现地方刺绣项目的家庭式传承关系。', '大冶刺绣教学与创作', 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0);
INSERT INTO ich_project (id, name, category_id, region_id, level, batch, protection_unit, cover_image, summary, content, longitude, latitude, status, view_count, featured, created_at, updated_at, deleted) VALUES
(1, '汉绣', 3, 1, '国家级', '第一批', '武汉汉绣保护中心', '/placeholder/project-placeholder.svg', '汉绣是湖北极具代表性的传统刺绣技艺，以色彩浓烈、纹样华丽和装饰性强著称。', '汉绣广泛应用于服饰、陈设和礼仪用品，体现荆楚审美与民间工艺智慧。平台以汉绣作为首页重点展示项目，用于演示图文、人物和统计联动。', '114.3055', '30.5928', 1, 286, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(2, '汉剧', 1, 1, '国家级', '第一批', '武汉汉剧院', '/placeholder/project-placeholder.svg', '汉剧是湖北最具影响力的地方剧种之一，对京剧等剧种的形成产生过重要影响。', '汉剧唱腔高亢、表演程式成熟，在武汉及周边地区拥有深厚群众基础。平台将其作为传统戏剧门类的核心案例。', '114.3055', '30.5928', 1, 198, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(3, '楚剧', 1, 1, '国家级', '第一批', '武汉楚剧院', '/placeholder/project-placeholder.svg', '楚剧源于湖北民间曲调，语言亲切、生活气息浓厚，是湖北戏曲文化的重要名片。', '楚剧长期活跃于武汉及江汉平原地区，在人物塑造和地方语言表达方面具有鲜明特色。该条目用于展示戏曲类项目的后台维护能力。', '114.3055', '30.5928', 1, 162, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(4, '武当武术', 4, 3, '国家级', '第二批', '武当山文化馆', '/placeholder/project-placeholder.svg', '武当武术依托武当山道教文化形成，兼具养生、技击和礼仪特征。', '武当武术在湖北非遗对外传播中辨识度极高，适合作为地图点位和热门项目排行的展示对象。', '110.7989', '32.6292', 1, 320, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(5, '武当山宫观道乐', 5, 3, '国家级', '第一批', '武当山道教协会', '/placeholder/project-placeholder.svg', '武当山宫观道乐是湖北传统音乐的重要组成部分，与武当山祭仪和道教活动密切相关。', '项目以器乐、吟唱和仪式性音乐为特色，能够丰富平台对传统音乐门类的展示层次。', '110.7989', '32.6292', 1, 122, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(6, '秭归端午习俗', 8, 4, '国家级', '第一批', '秭归县文化馆', '/placeholder/project-placeholder.svg', '秭归端午习俗与屈原文化深度相关，兼具纪念、祭祀和群众参与等多重意义。', '该项目适合在平台中呈现民俗类非遗的节庆场景、文化记忆与地域认同。', '111.2865', '30.6919', 1, 188, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(7, '长阳南曲', 6, 4, '国家级', '第一批', '长阳土家族自治县文化馆', '/placeholder/project-placeholder.svg', '长阳南曲兼具曲艺与地方音乐特征，是湖北少数民族地区具有代表性的说唱艺术。', '平台通过该项目展示曲艺类非遗的条目化管理方式，突出门类差异化。', '111.2865', '30.6919', 1, 108, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(8, '土家族撒叶儿嗬', 7, 13, '国家级', '第一批', '恩施州群众艺术馆', '/placeholder/project-placeholder.svg', '撒叶儿嗬是土家族极具生命力的传统舞蹈，具有强烈的群体性和礼俗性。', '该项目适合在平台中通过地图、统计和图文结合方式展示民族地区非遗的活态传承特点。', '109.4869', '30.2831', 1, 176, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(9, '恩施玉露制作技艺', 2, 13, '国家级', '第一批', '恩施州非遗保护中心', '/placeholder/project-placeholder.svg', '恩施玉露是中国蒸青针形绿茶代表，其传统制作技艺在湖北茶文化中具有重要地位。', '项目适合体现传统技艺类非遗从原料、工序到品牌传播的完整数据结构。', '109.4869', '30.2831', 1, 231, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(10, '沔阳雕花剪纸', 3, 14, '国家级', '第一批', '仙桃市文化馆', '/placeholder/project-placeholder.svg', '沔阳雕花剪纸图案繁复、层次鲜明，是江汉平原民间美术的重要代表。', '平台通过该项目可以展示传统美术类项目的图样、工艺与传承人关系。', '113.4539', '30.3649', 1, 214, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(11, '黄梅挑花', 3, 10, '国家级', '第一批', '黄梅县文化馆', '/placeholder/project-placeholder.svg', '黄梅挑花具有鲜明的民间生活审美，以挑、补、缀结合的刺绣技艺闻名。', '该项目可以与汉绣、大冶刺绣在前台形成对比展示，体现湖北刺绣类非遗的多样性。', '114.8724', '30.4535', 1, 146, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(12, '蕲春艾灸疗法', 9, 10, '国家级', '扩展项目', '蕲春县李时珍医院', '/placeholder/project-placeholder.svg', '蕲春艾灸疗法依托李时珍中医药文化传统，兼具诊疗实践和地方文化价值。', '该项目为平台提供传统医药门类样本，能够演示多传承人关联和特色门类管理。', '114.8724', '30.4535', 1, 205, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(13, '赵李桥砖茶制作技艺', 2, 11, '国家级', '第二批', '湖北赵李桥茶厂有限责任公司', '/placeholder/project-placeholder.svg', '赵李桥砖茶制作技艺是湖北传统茶制作的重要代表，在黑茶生产和商贸传播方面影响深远。', '该项目适合用于展示传统技艺类项目的企业保护单位和品牌传承场景。', '114.3224', '29.8413', 1, 152, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(14, '赤壁脚盆鼓', 7, 11, '省级', '湖北省名录', '赤壁市文化馆', '/placeholder/project-placeholder.svg', '脚盆鼓是赤壁地区具有民间节庆色彩的传统舞蹈项目，节奏鲜明、表演性强。', '平台可通过该项目展示省级项目与国家级项目并存的多层次结构。', '114.3224', '29.8413', 1, 88, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(15, '石花酒传统酿造技艺', 2, 5, '省级', '湖北省名录', '湖北石花酒业股份有限公司', '/placeholder/project-placeholder.svg', '石花酒传统酿造技艺体现了湖北地方酒文化和发酵工艺传统。', '项目有助于拓宽平台对传统技艺中酿造、发酵等工业化传承场景的展示。', '112.1441', '32.0437', 1, 97, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(16, '房县黄酒酿造技艺', 2, 3, '省级', '湖北省名录', '房县黄酒民俗文化研究中心', '/placeholder/project-placeholder.svg', '房县黄酒酿造技艺兼具日常饮食和地方礼俗功能，是十堰地区重要的传统酿造技艺。', '该项目适合与茶制作项目共同构成传统技艺门类下的多样化案例。', '110.7989', '32.6292', 1, 111, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(17, '鄂州雕花剪纸', 3, 6, '省级', '湖北省名录', '鄂州市文化馆', '/placeholder/project-placeholder.svg', '鄂州雕花剪纸构图饱满、刀法细腻，是湖北剪纸谱系中的重要支系。', '平台通过该项目与沔阳剪纸联动，展示同一门类在不同地区的风格差异。', '114.8949', '30.3919', 1, 119, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(18, '云梦皮影戏', 1, 8, '省级', '湖北省名录', '云梦县文化馆', '/placeholder/project-placeholder.svg', '云梦皮影戏融合地方唱腔、雕刻与操演技艺，具有综合性表演艺术特征。', '项目能够体现传统戏剧类非遗在视觉艺术和舞台艺术之间的交叉属性。', '113.9169', '30.9246', 1, 83, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(19, '孝感雕花剪纸', 3, 8, '省级', '湖北省名录', '孝感市非遗保护中心', '/placeholder/project-placeholder.svg', '孝感雕花剪纸是孝感地区民间剪纸传统的代表，题材多取材于民俗生活。', '平台可通过项目详情和地图检索让用户快速比较不同地市剪纸项目的分布。', '113.9169', '30.9246', 1, 79, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(20, '荆州花鼓戏', 1, 15, '国家级', '第一批', '湖北省花鼓戏艺术研究院', '/placeholder/project-placeholder.svg', '荆州花鼓戏唱腔明快、生活气息浓厚，是湖北花鼓戏系统中影响较大的剧种。', '项目适合与汉剧、楚剧一起构成门户端的戏曲专题展示，同时提供传承人关联样本。', '112.9000', '30.4015', 1, 168, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(21, '青林寺谜语', 10, 4, '国家级', '第二批', '宜都市文化馆', '/placeholder/project-placeholder.svg', '青林寺谜语是湖北民间文学代表项目，体现地方口头智慧和节庆娱乐传统。', '该项目帮助平台补足民间文学门类，实现非遗类别展示更加完整。', '111.2865', '30.6919', 1, 92, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(22, '楚式漆器髹饰技艺', 2, 9, '省级', '湖北省名录', '荆州漆器工艺保护中心', '/placeholder/project-placeholder.svg', '楚式漆器髹饰技艺体现楚文化工艺传统，具有较高审美与工艺研究价值。', '当前初始化数据将其设置为隐藏状态，用于演示后台隐藏项目不在前台公开显示的逻辑。', '112.2397', '30.3352', 0, 67, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(23, '监利草把龙', 7, 9, '省级', '湖北省名录', '监利市文化馆', '/placeholder/project-placeholder.svg', '草把龙是江汉平原地区具有节庆表演性质的传统舞蹈项目，现场感强。', '平台可通过舞蹈类项目进一步丰富不同门类在地图和统计图中的表现。', '112.2397', '30.3352', 1, 74, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(24, '宣恩薅草锣鼓', 5, 13, '省级', '湖北省名录', '宣恩县文化馆', '/placeholder/project-placeholder.svg', '薅草锣鼓在恩施地区兼具劳动组织与音乐娱乐双重功能。', '当前初始化数据将其设置为隐藏状态，用于测试后台维护后再公开发布的流程。', '109.4869', '30.2831', 0, 55, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(25, '武汉面塑', 3, 1, '省级', '湖北省名录', '武汉面塑艺术工作室', '/placeholder/project-placeholder.svg', '武汉面塑以小型人物和吉庆造型见长，是武汉都市民俗与手工艺结合的代表。', '项目适合在后台演示图片上传、传承人关联和详情图文展示等完整流程。', '114.3055', '30.5928', 1, 138, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(26, '长盛川青砖茶制作技艺', 2, 4, '省级', '湖北省名录', '湖北鑫鼎生物科技有限公司', '/placeholder/project-placeholder.svg', '长盛川青砖茶制作技艺延续古老茶路贸易传统，是湖北传统茶技艺的代表项目之一。', '平台用该项目演示一个项目关联多位传承人、支持导出和统计分析的完整场景。', '111.2865', '30.6919', 1, 173, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(27, '大冶刺绣', 3, 2, '省级', '湖北省名录', '大冶刺绣艺术馆', '/placeholder/project-placeholder.svg', '大冶刺绣融合地方民俗题材与现代审美表达，是湖北刺绣类非遗中的年轻化案例。', '该项目与汉绣、黄梅挑花共同构成平台的湖北刺绣专题展示。', '115.0389', '30.1997', 1, 121, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(28, '随州炎帝祭典', 8, 12, '国家级', '第二批', '炎帝故里风景名胜区管理委员会', '/placeholder/project-placeholder.svg', '炎帝祭典承载华夏始祖文化记忆，在湖北民俗和公共文化活动中具有重要地位。', '项目适合在平台中展示大型民俗活动的地域性和公众参与属性。', '113.3831', '31.6901', 1, 142, 1, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(29, '郧西七夕', 8, 3, '国家级', '第二批', '郧西县文化馆', '/placeholder/project-placeholder.svg', '郧西七夕以牛郎织女传说和地方婚俗文化闻名，是湖北代表性民俗项目。', '该项目可用于展示节庆、婚俗与民间文学交叉形成的复合型文化内涵。', '110.7989', '32.6292', 1, 106, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0),
(30, '天门糖塑', 3, 16, '省级', '湖北省名录', '天门市文化馆', '/placeholder/project-placeholder.svg', '天门糖塑以民间节庆和市集表演为主要场景，兼具即时制作和民间审美特色。', '项目为传统美术门类增加更多市州覆盖点位，便于地图检索页面形成均衡分布。', '113.1658', '30.6531', 1, 69, 0, '2026-03-29 12:00:00', '2026-03-29 12:00:00', 0);
